229→	// Check for cloud deploy mode only on first execution
230→	// Read env var name in uppercase: DEPLOY
231→	deployEnv := os.Getenv("DEPLOY")
232→	if deployEnv == "cloud" {
233→		isCloudDeploy = true
234→	}
235→
236→	// Determine and load the configuration file.
237→	// Prefer the Postgres store when configured, otherwise fallback to git or local files.
238→	var configFilePath string
239→	if usePostgresStore {
240→		if pgStoreLocalPath == "" {
241→			pgStoreLocalPath = wd
242→		}
243→		pgStoreLocalPath = filepath.Join(pgStoreLocalPath, "pgstore")
244→		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
245→		pgStoreInst, err = store.NewPostgresStore(ctx, store.PostgresStoreConfig{
246→			DSN:      pgStoreDSN,
247→			Schema:   pgStoreSchema,
248→			SpoolDir: pgStoreLocalPath,
249→		})
250→		cancel()
251→		if err != nil {
252→			log.Errorf("failed to initialize postgres token store: %v", err)
253→			return
254→		}
255→		examplePath := filepath.Join(wd, "config.example.yaml")
256→		ctx, cancel = context.WithTimeout(context.Background(), 30*time.Second)
257→		if errBootstrap := pgStoreInst.Bootstrap(ctx, examplePath); errBootstrap != nil {
258→			cancel()
259→			log.Errorf("failed to bootstrap postgres-backed config: %v", errBootstrap)
260→			return
261→		}
262→		cancel()
263→		configFilePath = pgStoreInst.ConfigPath()
264→		cfg, err = config.LoadConfigOptional(configFilePath, isCloudDeploy)
265→		if err == nil {
266→			cfg.AuthDir = pgStoreInst.AuthDir()
267→			log.Infof("postgres-backed token store enabled, workspace path: %s", pgStoreInst.WorkDir())
268→		}
269→	} else if useObjectStore {
270→		if objectStoreLocalPath == "" {
271→			if writableBase != "" {
272→				objectStoreLocalPath = writableBase
273→			} else {
274→				objectStoreLocalPath = wd
275→			}
276→		}
277→		objectStoreRoot := filepath.Join(objectStoreLocalPath, "objectstore")
278→		resolvedEndpoint := strings.TrimSpace(objectStoreEndpoint)
279→		useSSL := true
280→		if strings.Contains(resolvedEndpoint, "://") {
281→			parsed, errParse := url.Parse(resolvedEndpoint)
282→			if errParse != nil {
283→				log.Errorf("failed to parse object store endpoint %q: %v", objectStoreEndpoint, errParse)
284→				return
285→			}
286→			switch strings.ToLower(parsed.Scheme) {
287→			case "http":
288→				useSSL = false
289→			case "https":
290→				useSSL = true
291→			default:
292→				log.Errorf("unsupported object store scheme %q (only http and https are allowed)", parsed.Scheme)
293→				return
294→			}
295→			if parsed.Host == "" {
296→				log.Errorf("object store endpoint %q is missing host information", objectStoreEndpoint)
297→				return
298→			}
299→			resolvedEndpoint = parsed.Host
300→			if parsed.Path != "" && parsed.Path != "/" {
301→				resolvedEndpoint = strings.TrimSuffix(parsed.Host+parsed.Path, "/")
302→			}
303→		}
304→		resolvedEndpoint = strings.TrimRight(resolvedEndpoint, "/")
305→		objCfg := store.ObjectStoreConfig{
306→			Endpoint:  resolvedEndpoint,
307→			Bucket:    objectStoreBucket,
308→			AccessKey: objectStoreAccess,
309→			SecretKey: objectStoreSecret,
310→			LocalRoot: objectStoreRoot,
311→			UseSSL:    useSSL,
312→			PathStyle: true,
313→		}
314→		objectStoreInst, err = store.NewObjectTokenStore(objCfg)
315→		if err != nil {
316→			log.Errorf("failed to initialize object token store: %v", err)
317→			return
318→		}
319→		examplePath := filepath.Join(wd, "config.example.yaml")
320→		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
321→		if errBootstrap := objectStoreInst.Bootstrap(ctx, examplePath); errBootstrap != nil {
322→			cancel()
323→			log.Errorf("failed to bootstrap object-backed config: %v", errBootstrap)
324→			return
325→		}
326→		cancel()
327→		configFilePath = objectStoreInst.ConfigPath()
328→		cfg, err = config.LoadConfigOptional(configFilePath, isCloudDeploy)
329→		if err == nil {
330→			if cfg == nil {
331→				cfg = &config.Config{}
332→			}
333→			cfg.AuthDir = objectStoreInst.AuthDir()
334→			log.Infof("object-backed token store enabled, bucket: %s", objectStoreBucket)
335→		}
336→	} else if useGitStore {
337→		if gitStoreLocalPath == "" {
338→			if writableBase != "" {
339→				gitStoreLocalPath = writableBase
340→			} else {
341→				gitStoreLocalPath = wd
342→			}
343→		}
344→		gitStoreRoot = filepath.Join(gitStoreLocalPath, "gitstore")
345→		authDir := filepath.Join(gitStoreRoot, "auths")
346→		gitStoreInst = store.NewGitTokenStore(gitStoreRemoteURL, gitStoreUser, gitStorePassword)
347→		gitStoreInst.SetBaseDir(authDir)
348→		if errRepo := gitStoreInst.EnsureRepository(); errRepo != nil {
349→			log.Errorf("failed to prepare git token store: %v", errRepo)
350→			return
351→		}
352→		configFilePath = gitStoreInst.ConfigPath()
353→		if configFilePath == "" {
354→			configFilePath = filepath.Join(gitStoreRoot, "config", "config.yaml")
355→		}
356→		if _, statErr := os.Stat(configFilePath); errors.Is(statErr, fs.ErrNotExist) {
357→			examplePath := filepath.Join(wd, "config.example.yaml")
358→			if _, errExample := os.Stat(examplePath); errExample != nil {
359→				log.Errorf("failed to find template config file: %v", errExample)
360→				return
361→			}
362→			if errCopy := misc.CopyConfigTemplate(examplePath, configFilePath); errCopy != nil {
363→				log.Errorf("failed to bootstrap git-backed config: %v", errCopy)
364→				return
365→			}
366→			if errCommit := gitStoreInst.PersistConfig(context.Background()); errCommit != nil {
367→				log.Errorf("failed to commit initial git-backed config: %v", errCommit)
368→				return
369→			}
370→			log.Infof("git-backed config initialized from template: %s", configFilePath)
371→		} else if statErr != nil {
372→			log.Errorf("failed to inspect git-backed config: %v", statErr)
373→			return
374→		}
375→		cfg, err = config.LoadConfigOptional(configFilePath, isCloudDeploy)
376→		if err == nil {
377→			cfg.AuthDir = gitStoreInst.AuthDir()
378→			log.Infof("git-backed token store enabled, repository path: %s", gitStoreRoot)
379→		}
380→	} else if configPath != "" {
381→		configFilePath = configPath
382→		cfg, err = config.LoadConfigOptional(configPath, isCloudDeploy)
383→	} else {
384→		wd, err = os.Getwd()
385→		if err != nil {
386→			log.Errorf("failed to get working directory: %v", err)
387→			return
388→		}
389→		configFilePath = filepath.Join(wd, "config.yaml")
390→		cfg, err = config.LoadConfigOptional(configFilePath, isCloudDeploy)
391→	}
392→	if err != nil {
393→		log.Errorf("failed to load config: %v", err)
394→		return
395→	}
396→	if cfg == nil {
397→		cfg = &config.Config{}
398→	}
399→
400→	// In cloud deploy mode, check if we have a valid configuration
401→	var configFileExists bool
402→	if isCloudDeploy {
403→		if info, errStat := os.Stat(configFilePath); errStat != nil {
404→			// Don't mislead: API server will not start until configuration is provided.
405→			log.Info("Cloud deploy mode: No configuration file detected; standing by for configuration")
406→			configFileExists = false
407→		} else if info.IsDir() {
408→			log.Info("Cloud deploy mode: Config path is a directory; standing by for configuration")
409→			configFileExists = false
410→		} else if cfg.Port == 0 {
411→			// LoadConfigOptional returns empty config when file is empty or invalid.
412→			// Config file exists but is empty or invalid; treat as missing config
413→			log.Info("Cloud deploy mode: Configuration file is empty or invalid; standing by for valid configuration")
414→			configFileExists = false
415→		} else {
416→			log.Info("Cloud deploy mode: Configuration file detected; starting service")
417→			configFileExists = true
418→		}
419→	}
420→	usage.SetStatisticsEnabled(cfg.UsageStatisticsEnabled)
421→	coreauth.SetQuotaCooldownDisabled(cfg.DisableCooling)
422→
423→	if err = logging.ConfigureLogOutput(cfg); err != nil {
424→		log.Errorf("failed to configure log output: %v", err)
425→		return
426→	}
427→
428→	log.Infof("CLIProxyAPI Version: %s, Commit: %s, BuiltAt: %s", buildinfo.Version, buildinfo.Commit, buildinfo.BuildDate)
429→
430→	// Set the log level based on the configuration.
431→	util.SetLogLevel(cfg)
432→
433→	if resolvedAuthDir, errResolveAuthDir := util.ResolveAuthDir(cfg.AuthDir); errResolveAuthDir != nil {
434→		log.Errorf("failed to resolve auth directory: %v", errResolveAuthDir)
435→		return
436→	} else {
437→		cfg.AuthDir = resolvedAuthDir
438→	}
439→	managementasset.SetCurrentConfig(cfg)
440→
441→	// Create login options to be used in authentication flows.
442→	options := &cmd.LoginOptions{
443→		NoBrowser:    noBrowser,
444→		CallbackPort: oauthCallbackPort,
445→	}
446→
447→	// Register the shared token store once so all components use the same persistence backend.
448→	if usePostgresStore {
449→		sdkAuth.RegisterTokenStore(pgStoreInst)
450→	} else if useObjectStore {
451→		sdkAuth.RegisterTokenStore(objectStoreInst)
452→	} else if useGitStore {
453→		sdkAuth.RegisterTokenStore(gitStoreInst)
454→	} else {
455→		sdkAuth.RegisterTokenStore(sdkAuth.NewFileTokenStore())
456→	}
457→
458→	// Register built-in access providers before constructing services.
459→	configaccess.Register(&cfg.SDKConfig)
460→
461→	// Handle different command modes based on the provided flags.
462→
463→	if vertexImport != "" {
464→		// Handle Vertex service account import
465→		cmd.DoVertexImport(cfg, vertexImport)
466→	} else if login {
467→		// Handle Google/Gemini login
468→		cmd.DoLogin(cfg, projectID, options)
469→	} else if antigravityLogin {
470→		// Handle Antigravity login
471→		cmd.DoAntigravityLogin(cfg, options)
472→	} else if codexLogin {
473→		// Handle Codex login
474→		cmd.DoCodexLogin(cfg, options)
475→	} else if codexDeviceLogin {
476→		// Handle Codex device-code login
477→		cmd.DoCodexDeviceLogin(cfg, options)
478→	} else if claudeLogin {
479→		// Handle Claude login
480→		cmd.DoClaudeLogin(cfg, options)
481→	} else if qwenLogin {
482→		cmd.DoQwenLogin(cfg, options)
483→	} else if iflowLogin {
484→		cmd.DoIFlowLogin(cfg, options)
485→	} else if iflowCookie {
486→		cmd.DoIFlowCookieAuth(cfg, options)
487→	} else if kimiLogin {
488→		cmd.DoKimiLogin(cfg, options)
489→	} else {
490→		// In cloud deploy mode without config file, just wait for shutdown signals
491→		if isCloudDeploy && !configFileExists {
492→			// No config file available, just wait for shutdown
493→			cmd.WaitForCloudDeploy()
494→			return
495→		}
496→		if localModel && (!tuiMode || standalone) {
497→			log.Info("Local model mode: using embedded model catalog, remote model updates disabled")
498→		}
499→		if tuiMode {
500→			if standalone {
501→				// Standalone mode: start an embedded local server and connect TUI client to it.
502→				managementasset.StartAutoUpdater(context.Background(), configFilePath)
503→				if !localModel {
504→					registry.StartModelsUpdater(context.Background())
505→				}
506→				hook := tui.NewLogHook(2000)
507→				hook.SetFormatter(&logging.LogFormatter{})
508→				log.AddHook(hook)
509→
510→				origStdout := os.Stdout
511→				origStderr := os.Stderr
512→				origLogOutput := log.StandardLogger().Out
513→				log.SetOutput(io.Discard)
514→
515→				devNull, errOpenDevNull := os.Open(os.DevNull)
516→				if errOpenDevNull == nil {
517→					os.Stdout = devNull
518→					os.Stderr = devNull
519→				}
520→
521→				restoreIO := func() {
522→					os.Stdout = origStdout
523→					os.Stderr = origStderr
524→					log.SetOutput(origLogOutput)
525→					if devNull != nil {
526→						_ = devNull.Close()
527→					}
528→				}
529→
530→				localMgmtPassword := fmt.Sprintf("tui-%d-%d", os.Getpid(), time.Now().UnixNano())
531→				if password == "" {
532→					password = localMgmtPassword
533→				}
534→
535→				cancel, done := cmd.StartServiceBackground(cfg, configFilePath, password)
536→
537→				client := tui.NewClient(cfg.Port, password)
538→				ready := false
539→				backoff := 100 * time.Millisecond
540→				for i := 0; i < 30; i++ {
541→					if _, errGetConfig := client.GetConfig(); errGetConfig == nil {
542→						ready = true
543→						break
544→					}
545→					time.Sleep(backoff)
546→					if backoff < time.Second {
547→						backoff = time.Duration(float64(backoff) * 1.5)
548→					}
549→				}
550→
551→				if !ready {
552→					restoreIO()
553→					cancel()
554→					<-done
555→					fmt.Fprintf(os.Stderr, "TUI error: embedded server is not ready\n")
556→					return
557→				}
558→
559→				if errRun := tui.Run(cfg.Port, password, hook, origStdout); errRun != nil {
560→					restoreIO()
561→					fmt.Fprintf(os.Stderr, "TUI error: %v\n", errRun)
562→				} else {
563→					restoreIO()
564→				}
565→
566→				cancel()
567→				<-done
568→			} else {
569→				// Default TUI mode: pure management client.
570→				// The proxy server must already be running.
571→				if errRun := tui.Run(cfg.Port, password, nil, os.Stdout); errRun != nil {
572→					fmt.Fprintf(os.Stderr, "TUI error: %v\n", errRun)
573→				}
574→			}
575→		} else {
576→			// Start the main proxy service
577→			managementasset.StartAutoUpdater(context.Background(), configFilePath)
578→			if !localModel {
579→				registry.StartModelsUpdater(context.Background())
580→			}
581→			cmd.StartService(cfg, configFilePath, password)
582→		}
583→	}
584→}
