147→// Middleware enforces access control for management endpoints.
148→// All requests (local and remote) require a valid management key.
149→// Additionally, remote access requires allow-remote-management=true.
150→func (h *Handler) Middleware() gin.HandlerFunc {
151→	const maxFailures = 5
152→	const banDuration = 30 * time.Minute
153→
154→	return func(c *gin.Context) {
155→		c.Header("X-CPA-VERSION", buildinfo.Version)
156→		c.Header("X-CPA-COMMIT", buildinfo.Commit)
157→		c.Header("X-CPA-BUILD-DATE", buildinfo.BuildDate)
158→
159→		clientIP := c.ClientIP()
160→		localClient := clientIP == "127.0.0.1" || clientIP == "::1"
161→		localPasswordEnabled := localClient && strings.TrimSpace(h.localPassword) != ""
162→		cfg := h.cfg
163→		var (
164→			allowRemote bool
165→			secretHash  string
166→		)
167→		if cfg != nil {
168→			allowRemote = cfg.RemoteManagement.AllowRemote
169→			secretHash = cfg.RemoteManagement.SecretKey
170→		}
171→		if h.allowRemoteOverride {
172→			allowRemote = true
173→		}
174→		envSecret := h.envSecret
175→
176→		fail := func() {}
177→		if !localClient {
178→			h.attemptsMu.Lock()
179→			ai := h.failedAttempts[clientIP]
180→			if ai != nil {
181→				if !ai.blockedUntil.IsZero() {
182→					if time.Now().Before(ai.blockedUntil) {
183→						remaining := time.Until(ai.blockedUntil).Round(time.Second)
184→						h.attemptsMu.Unlock()
185→						c.AbortWithStatusJSON(http.StatusForbidden, gin.H{"error": fmt.Sprintf("IP banned due to too many failed attempts. Try again in %s", remaining)})
186→						return
187→					}
188→					// Ban expired, reset state
189→					ai.blockedUntil = time.Time{}
190→					ai.count = 0
191→				}
192→			}
193→			h.attemptsMu.Unlock()
194→
195→			if !allowRemote {
196→				c.AbortWithStatusJSON(http.StatusForbidden, gin.H{"error": "remote management disabled"})
197→				return
198→			}
199→
200→			fail = func() {
201→				h.attemptsMu.Lock()
202→				aip := h.failedAttempts[clientIP]
203→				if aip == nil {
204→					aip = &attemptInfo{}
205→					h.failedAttempts[clientIP] = aip
206→				}
207→				aip.count++
208→				aip.lastActivity = time.Now()
209→				if aip.count >= maxFailures {
210→					aip.blockedUntil = time.Now().Add(banDuration)
211→					aip.count = 0
212→				}
213→				h.attemptsMu.Unlock()
214→			}
215→		}
216→		if secretHash == "" && envSecret == "" && !localPasswordEnabled {
217→			c.AbortWithStatusJSON(http.StatusForbidden, gin.H{"error": "remote management key not set"})
218→			return
219→		}
220→
221→		// Accept either Authorization: Bearer <key> or X-Management-Key
222→		var provided string
223→		if ah := c.GetHeader("Authorization"); ah != "" {
224→			parts := strings.SplitN(ah, " ", 2)
225→			if len(parts) == 2 && strings.ToLower(parts[0]) == "bearer" {
226→				provided = parts[1]
227→			} else {
228→				provided = ah
229→			}
230→		}
231→		if provided == "" {
232→			provided = c.GetHeader("X-Management-Key")
233→		}
234→
235→		if provided == "" {
236→			if !localClient {
237→				fail()
238→			}
239→			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing management key"})
240→			return
241→		}
242→
243→		if localPasswordEnabled {
244→			if lp := h.localPassword; lp != "" {
245→				if subtle.ConstantTimeCompare([]byte(provided), []byte(lp)) == 1 {
246→					c.Next()
247→					return
248→				}
249→			}
250→		}
251→
252→		if envSecret != "" && subtle.ConstantTimeCompare([]byte(provided), []byte(envSecret)) == 1 {
253→			if !localClient {
254→				h.attemptsMu.Lock()
255→				if ai := h.failedAttempts[clientIP]; ai != nil {
256→					ai.count = 0
257→					ai.blockedUntil = time.Time{}
258→				}
259→				h.attemptsMu.Unlock()
260→			}

